using cCoder.ClientRelationshipManagement.Platform.Models.Entities;using cCoder.ClientRelationshipManagement.Services.Entities;using Microsoft.AspNetCore.Mvc;using Microsoft.AspNetCore.OData.Deltas;using Microsoft.AspNetCore.OData.Query;using Microsoft.AspNetCore.OData.Results;using Microsoft.AspNetCore.OData.Routing.Controllers;using Microsoft.EntityFrameworkCore;
namespace cCoder.ClientRelationshipManagement.Api.Controllers;
[CrmUserAuthorize]public sealed class ProcessStepTaskAttemptsController(IProcessStepTaskAttemptOrchestrationService o):ODataController{static readonly HashSet<string>S=new(StringComparer.OrdinalIgnoreCase){"Id","CreatedOn","CreatedBy","LastUpdated","LastUpdatedBy"};[EnableQuery(MaxExpansionDepth=8)]public IActionResult Get()=>Ok(o.RetrieveAll());[EnableQuery(MaxExpansionDepth=8)]public IActionResult Get([FromRoute]Guid key)=>Ok(SingleResult.Create(o.RetrieveAll().Where(x=>x.Id==key)));public async Task<IActionResult>Post([FromBody]ProcessStepTaskAttempt x,CancellationToken t)=>Created(await o.AddAsync(x,t));public async Task<IActionResult>Put([FromRoute]Guid key,[FromBody]ProcessStepTaskAttempt x,CancellationToken t){if(!await o.RetrieveWriteable().AnyAsync(y=>y.Id==key,t))return NotFound();x.Id=key;return Updated(await o.ModifyAsync(x,t));}[AcceptVerbs("PATCH","MERGE")]public async Task<IActionResult>Patch([FromRoute]Guid key,Delta<ProcessStepTaskAttempt>d,CancellationToken t){var x=await o.RetrieveWriteable().SingleOrDefaultAsync(y=>y.Id==key,t);if(x is null)return NotFound();var p=d.GetChangedPropertyNames().FirstOrDefault(S.Contains);if(p is not null)return BadRequest($"Property '{p}' is server-managed.");d.Patch(x);x.Id=key;return Updated(await o.ModifyAsync(x,t));}public async Task<IActionResult>Delete([FromRoute]Guid key,CancellationToken t){var x=await o.RetrieveWriteable().SingleOrDefaultAsync(y=>y.Id==key,t);if(x is null)return NotFound();await o.RemoveAsync(x,t);return NoContent();}}
